// vectorGrid.js
class VectorGrid {
  constructor(opts = {}) {
    this.cell = opts.cell ?? 24;
    this.noiseScale = opts.noiseScale ?? 0.06;
    this.zSpeed = opts.zSpeed ?? 0.01;
    this.arrowScale = opts.arrowScale ?? 0.42;
    this.bg = opts.bg ?? 245;

    this.zoff = 0;
  }

  // white (noise=1) => 0 degrees
  // black (noise=0) => 360 degrees (same direction as 0, but mapped as TWO_PI)
  noiseToAngle(n) {
    return (1 - n) * TWO_PI;
  }

  draw(vectorDrawer) {
    background(this.bg);

    const cell = this.cell;
    const ns = this.noiseScale;

    for (let y = 0; y < height; y += cell) {
      for (let x = 0; x < width; x += cell) {
        const cx = x + cell * 0.5;
        const cy = y + cell * 0.5;

        const n = noise(x * ns, y * ns, this.zoff); // 0..1
        const angle = this.noiseToAngle(n);

        const len = cell * this.arrowScale;
        const x2 = cx + cos(angle) * len;
        const y2 = cy + sin(angle) * len;

        vectorDrawer.drawFromPoints(cx, cy, x2, y2);
      }
    }

    this.zoff += this.zSpeed; // comment out or set zSpeed=0 for static
  }
}

