// Flow-field mover with separation + jitter + wrap + visuals + SEGMENTED TRAILS (wrap-safe)

class Mover {
  constructor(x = 0, y = 0, opts = {}) {
    this.position = createVector(x, y);
    this.velocity = createVector();
    this.acceleration = createVector();

    // motion
    this.maxSpeed = opts.maxSpeed ?? 3.5;
    this.fieldInfluence = opts.fieldInfluence ?? 0.25;

    // separation
    this.sepDist = opts.sepDist ?? 50;
    this.sepStrength = opts.sepStrength ?? 1.2;
    this.sepMaxForce = opts.sepMaxForce ?? 0.25;

    // jitter
    this.jitter = opts.jitter ?? 0.02;
    this.jitterScale = opts.jitterScale ?? 0.01;
    this._joff = random(1000);

    // visuals
    this.radius = opts.radius ?? 20;

    this.fillCol = opts.fillCol ?? 255;
    this.strokeCol = opts.strokeCol ?? 0;
    this.strokeW = opts.strokeW ?? 2;

    this.showArrow = opts.showArrow ?? true;

    this.arrowMode = opts.arrowMode ?? "speed"; // "fixed" | "speed"
    this.arrowLenScale = opts.arrowLenScale ?? 1.2;
    this.arrowSpeedScale = opts.arrowSpeedScale ?? 10;
    this.arrowMinLen = opts.arrowMinLen ?? 6;
    this.arrowMaxLen = opts.arrowMaxLen ?? 40;

    this.centerDot = opts.centerDot ?? true;
    this.centerDotSize = opts.centerDotSize ?? 4;
    this.centerDotCol = opts.centerDotCol ?? 0;

    // trails (SEGMENTED so wrap doesn't draw a cross-canvas line)
    this.trailOn = opts.trailOn ?? true;
    this.trailLen = opts.trailLen ?? 120; // total points across all segments
    this.trailWeight = opts.trailWeight ?? 2;
    this.trailCol = opts.trailCol ?? 0;
    this.trailAlpha = opts.trailAlpha ?? 90;
    this.trailMode = opts.trailMode ?? "points"; // "points" | "dots"

    this.trailSegments = [[]]; // array of segments, each segment is an array of p5.Vectors
    this._pushTrailPoint();
  }

  applyForce(f) {
    this.acceleration.add(f);
  }

  followField(field) {
    const force = field.getVectorAt(this.position.x, this.position.y);
    force.mult(this.fieldInfluence);
    this.applyForce(force);
  }

  separate(others) {
    let steer = createVector(0, 0);
    let count = 0;

    for (let o of others) {
      if (o === this) continue;
      const d = p5.Vector.dist(this.position, o.position);

      if (d > 0 && d < this.sepDist) {
        let diff = p5.Vector.sub(this.position, o.position);
        diff.normalize();
        diff.div(d);
        steer.add(diff);
        count++;
      }
    }

    if (count > 0) {
      steer.div(count);
      steer.setMag(this.maxSpeed);
      steer.sub(this.velocity);
      steer.limit(this.sepMaxForce);
      steer.mult(this.sepStrength);
      this.applyForce(steer);
    }
  }

  applyJitter() {
    if (this.jitter <= 0) return;

    const a =
      noise(
        this.position.x * this.jitterScale,
        this.position.y * this.jitterScale,
        this._joff
      ) *
      TWO_PI *
      2;

    const f = p5.Vector.fromAngle(a).mult(this.jitter);
    this.applyForce(f);
    this._joff += 0.01;
  }

  update() {
    this.velocity.add(this.acceleration);
    this.velocity.limit(this.maxSpeed);
    this.position.add(this.velocity);
    this.acceleration.mult(0);

    this._pushTrailPoint();
  }

  // ✅ wrap around; if wrap happens, start a new trail segment (don’t clear)
  wrapEdges() {
    const r = this.radius;
    let wrapped = false;

    if (this.position.x > width + r) {
      this.position.x = -r;
      wrapped = true;
    } else if (this.position.x < -r) {
      this.position.x = width + r;
      wrapped = true;
    }

    if (this.position.y > height + r) {
      this.position.y = -r;
      wrapped = true;
    } else if (this.position.y < -r) {
      this.position.y = height + r;
      wrapped = true;
    }

    if (wrapped && this.trailOn) {
      this._breakTrailSegment();   // ✅ key: prevents cross-screen line
      this._pushTrailPoint();      // seed new segment at wrapped location
    }

    return wrapped;
  }

  // ---------- TRAILS (segmented) ----------
  _breakTrailSegment() {
    // Only create a new segment if the current one has points
    const cur = this.trailSegments[this.trailSegments.length - 1];
    if (cur.length > 0) this.trailSegments.push([]);
  }

  _pushTrailPoint() {
    if (!this.trailOn) return;

    const cur = this.trailSegments[this.trailSegments.length - 1];
    cur.push(this.position.copy());

    this._trimTrailToMaxPoints();
  }

  _totalTrailPoints() {
    let total = 0;
    for (const seg of this.trailSegments) total += seg.length;
    return total;
  }

  _trimTrailToMaxPoints() {
    // Keep total points across ALL segments <= trailLen
    let total = this._totalTrailPoints();
    while (total > this.trailLen && this.trailSegments.length > 0) {
      const first = this.trailSegments[0];
      if (first.length > 0) {
        first.shift();
        total--;
      } else {
        // remove empty segments
        this.trailSegments.shift();
      }
    }

    // Ensure we always have at least one segment
    if (this.trailSegments.length === 0) this.trailSegments = [[]];
  }

  _withAlpha(col, a) {
    if (typeof col === "number") return color(col, a);
    return color(red(col), green(col), blue(col), a);
  }

  drawTrail() {
    if (!this.trailOn) return;

    push();
    noFill();

    if (this.trailMode === "points") {
      stroke(this._withAlpha(this.trailCol, this.trailAlpha));
      strokeWeight(this.trailWeight);

      for (const seg of this.trailSegments) {
        if (seg.length < 2) continue;
        beginShape();
        for (const p of seg) vertex(p.x, p.y);
        endShape();
      }
    } else {
      // "dots" with fade-in along each segment
      noStroke();
      for (const seg of this.trailSegments) {
        if (seg.length === 0) continue;
        for (let i = 0; i < seg.length; i++) {
          const t = seg.length === 1 ? 1 : i / (seg.length - 1);
          const a = this.trailAlpha * t;
          fill(this._withAlpha(this.trailCol, a));
          const p = seg[i];
          circle(p.x, p.y, this.trailWeight);
        }
      }
