// mover.js
// Updated: visual properties are configurable per-mover.
// - You can set: radius, fill/stroke colors, stroke weights, arrow style,
//   arrow length behavior, and whether to show the arrow at all.

class Mover {
  constructor(x = 0, y = 0, opts = {}) {
    this.position = createVector(x, y);
    this.velocity = createVector();
    this.acceleration = createVector();

    // =========================
    // Motion tuning
    // =========================
    this.maxSpeed = opts.maxSpeed ?? 4.0;
    this.fieldInfluence = opts.fieldInfluence ?? 0.3;

    // =========================
    // Visual tuning
    // =========================
    this.radius = opts.radius ?? 28;

    // ball appearance
    this.fillCol = opts.fillCol ?? 255;          // number or p5 color()
    this.strokeCol = opts.strokeCol ?? 0;        // number or p5 color()
    this.strokeW = opts.strokeW ?? 2;

    // arrow appearance (uses VectorDrawer instance passed to display())
    this.showArrow = opts.showArrow ?? true;

    // Arrow length behavior:
    // - "fixed": arrow length = radius * arrowLenScale
    // - "speed": arrow length scales with speed (clamped), good for reading motion
    this.arrowMode = opts.arrowMode ?? "fixed"; // "fixed" | "speed"
    this.arrowLenScale = opts.arrowLenScale ?? 1.2; // used in fixed mode
    this.arrowSpeedScale = opts.arrowSpeedScale ?? 14; // used in speed mode
    this.arrowMinLen = opts.arrowMinLen ?? 6;
    this.arrowMaxLen = opts.arrowMaxLen ?? this.radius * 1.8;

    // optional: draw a faint "center dot"
    this.centerDot = opts.centerDot ?? false;
    this.centerDotSize = opts.centerDotSize ?? 4;
    this.centerDotCol = opts.centerDotCol ?? 0;
  }

  // -------------------------
  // Motion
  // -------------------------
  applyForce(f) {
    this.acceleration.add(f);
  }

  followField(field) {
    const force = field.getVectorAt(this.position.x, this.position.y);
    force.mult(this.fieldInfluence);
    this.velocity.add(force);
  }

  update() {
    this.velocity.add(this.acceleration);
    this.velocity.limit(this.maxSpeed);
    this.position.add(this.velocity);
    this.acceleration.mult(0);
  }

  wrapEdges() {
    const r = this.radius;

    if (this.position.x > width + r) this.position.x = -r;
    if (this.position.x < -r) this.position.x = width + r;

    if (this.position.y > height + r) this.position.y = -r;
    if (this.position.y < -r) this.position.y = height + r;
  }

  // -------------------------
  // Render helpers
  // -------------------------
  _computeArrowLen() {
    if (this.arrowMode === "speed") {
      const spd = this.velocity.mag();
      const len = spd * this.arrowSpeedScale;
      return constrain(len, this.arrowMinLen, this.arrowMaxLen);
    }
    // fixed
    return this.radius * this.arrowLenScale;
  }

  // vectorDrawer is your shared VectorDrawer instance
  display(vectorDrawer) {
    // ball
    push();
    fill(this.fillCol);
    stroke(this.strokeCol);
    strokeWeight(this.strokeW);
    circle(this.position.x, this.position.y, this.radius * 2);

    if (this.centerDot) {
      noStroke();
      fill(this.centerDotCol);
      circle(this.position.x, this.position.y, this.centerDotSize);
    }
    pop();

    // arrow showing velocity direction
    if (this.showArrow) {
      const v = this.velocity.copy();
      if (v.mag() > 0.0001) {
        v.setMag(this._computeArrowLen());

        vectorDrawer.drawFromPoints(
          this.position.x,
          this.position.y,
          this.position.x + v.x,
          this.position.y + v.y
        );
      }
    }
  }
}

