// sketch.js
let movers = [];
let vDraw;
let vecGrid;

let light;
let light1;

const NUM_MOVERS = 50;

function setup() {
  createCanvas(400, 400);

  vDraw = new VectorDrawer({
    strokeCol: 0,
    fillCol: 0,
    headScale: 0.06,
    weightScale: 0.03,
    minHead: 0.02,
    maxHead: 30,
    minWeight: 1,
    maxWeight: 6,
  });

  vecGrid = new VectorGrid({
    cell: 10,
    noiseScale: 0.006,
    zSpeed: 0.01,
    arrowScale: 0.42,
    bg: 20,
  });

  movers = [];
  for (let i = 0; i < NUM_MOVERS; i++) {
    const m = new Mover(random(width), random(height), {
      radius: random(0.2,0.6),
      fillCol: color(255),
      strokeCol: color(0),
      strokeW: 0,

      showArrow: false,
      arrowMode: "speed",
      arrowSpeedScale: 10,
      arrowMaxLen: 40,

      fieldInfluence: 0.22,
      maxSpeed: 3.3,

      // anti-clump
      sepDist: 55,
      sepStrength: 1.3,
      sepMaxForce: 0.28,

      // anti-locking
      jitter: 0.02,
      jitterScale: 0.01,

      // trails
      trailOn: true,
      trailLen: random(6, 8),
      trailWeight: (0.1, 0.3),
      trailCol: color(240),
      trailAlpha: 90,
      trailMode: "points", // "points" or "dots"

      centerDot: false,
      centerDotSize: 4,
      centerDotCol: color(0),
    });

    m.velocity = p5.Vector.random2D().mult(random(1.5, 3.0));
    movers.push(m);
  }

  light = new Light(width * 0.2, height * 0.6, {
    size: 23,

    majorColors: [
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],

    minorColors: [
      "#ff0000",
      "#00ffff",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],
  });

  light1 = new Light(width * 0.8, height * 0.45, {
    size: 30,

    majorColors: [
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],

    minorColors: [
      "#ff0000",
      "#00ffff",
      "#ff0000",
      "#ff0000",
      "#00ffff",
      "#ff0000",
    ],
  });
}

function draw() {
  // If you want the trails to "persist" more, you can fade instead of redraw:
  background(20);
  // BUT vecGrid.draw() calls background() internally.
  // So we keep the vector grid as the background each frame.
  // vecGrid.draw(vDraw);

  for (let m of movers) {
    m.followField(vecGrid);
    m.separate(movers);
    m.applyJitter();

    m.update();
    m.wrapEdges();
    m.display(vDraw);
  }
  light.render();
  drawUnevenCurve();
  light1.render();
}

function drawUnevenCurve() {
  push();
  noStroke();
  fill(0);

  const steps = 140;
  const baseThickness = 0.05;

  // 👇 YOU control these
  const yStart = height * 0.65; // left side Y
  const yEnd = height * 0.35; // right side Y

  beginShape(TRIANGLE_STRIP);

  for (let i = 0; i <= steps; i++) {
    let t = i / steps;

    let x = lerp(0, width, t);

    // Linear interpolation between left & right
    let baseY = lerp(yStart, yEnd, t);

    // Add curve shape on top
    let curveOffset = sin(t * PI) * 30;

    let y = baseY + curveOffset;

    // uneven thickness
    let n = noise(t * 4, frameCount * 0.01);
    let thickness = baseThickness + map(n, 0, 1, -1, 3);

    vertex(x, y - thickness);
    vertex(x, y + thickness);
  }

  endShape();
  pop();
}

