// light.js
class Light {
  constructor(x = 0, y = 0, opts = {}) {
    this.x = x;
    this.y = y;

    this.size = opts.size ?? 10;

    // arrays of colors → determine ray count
    this.majorColors = opts.majorColors ?? ["#ffffff"];
    this.minorColors = opts.minorColors ?? [];

    this.majorLen = opts.majorLen ?? this.size * 2.2;
    this.minorLen = opts.minorLen ?? this.size * 1.4;

    this.majorWeight = opts.majorWeight ?? Math.max(1, this.size * 0.18);
    this.minorWeight = opts.minorWeight ?? Math.max(1, this.size * 0.10);

    this.coreAlpha = opts.coreAlpha ?? 180;
    this.rayAlpha = opts.rayAlpha ?? 140;

    this.rot = opts.rot ?? 0;
  }

  render() {
    push();
    translate(this.x, this.y);
    rotate(this.rot);

    // soft glow halo
    noStroke();
    for (let i = 4; i >= 1; i--) {
      const r = this.size * (0.9 + i * 0.55);
      fill(255, this.coreAlpha / (i + 1));
      circle(0, 0, r);
    }

    // ---------- MAJOR RAYS ----------
    const majorStep = TWO_PI / this.majorColors.length;

    strokeCap(ROUND);
    strokeWeight(this.majorWeight);

    this.majorColors.forEach((col, i) => {
      const a = i * majorStep;
      stroke(col);

      const x1 = Math.cos(a) * (this.size * 0.35);
      const y1 = Math.sin(a) * (this.size * 0.35);
      const x2 = Math.cos(a) * this.majorLen;
      const y2 = Math.sin(a) * this.majorLen;

      line(x1, y1, x2, y2);
    });

    // ---------- MINOR RAYS ----------
    if (this.minorColors.length > 0) {
      const minorStep = TWO_PI / this.minorColors.length;
      const offset = minorStep * 0.5;

      strokeWeight(this.minorWeight);

      this.minorColors.forEach((col, i) => {
        const a = i * minorStep + offset;
        stroke(col);

        const x1 = Math.cos(a) * (this.size * 0.35);
        const y1 = Math.sin(a) * (this.size * 0.35);
        const x2 = Math.cos(a) * this.minorLen;
        const y2 = Math.sin(a) * this.minorLen;

        line(x1, y1, x2, y2);
      });
    }

    // bright core
    noStroke();
    fill(255);
    circle(0, 0, this.size);

    pop();
  }
}

