class FissileAtom extends Mover {
  constructor(x, y, opts = {}) {
    super(x, y);

    this.radius = opts.radius ?? 18;

    // Instability system
    this.instability = 0; // 0 → 1
    this.threshold = opts.threshold ?? 1.0;

    // How much a neutron increases instability
    this.absorbGain = opts.absorbGain ?? 0.35;

    // Optional slow spontaneous decay toward fission
    this.baseDecay = opts.baseDecay ?? 0.0005;

    this.fissioned = false;
  }

  // Called every frame
  updateAtom() {
    if (this.fissioned) return;

    // Slow natural instability increase (optional realism)
    this.instability += this.baseDecay;
    this.instability = constrain(this.instability, 0, 1.5);
  }

  // Called when a neutron hits
  absorb(neutron) {
    if (this.fissioned) return;

    const energy = neutron.energy ?? 1.0;

    // Nonlinear sensitivity (accelerates near critical)
    const sensitivity = 1 + pow(this.instability, 2) * 2;

