let atoms = [];
let neutrons = [];

const NUM_ATOMS = 260;

function setup() {
  createCanvas(600, 600);

  // Create atoms (mostly stationary)
  // --- Create atoms on a hexagonal grid ---
  atoms = [];

  const margin = 50;

  // pick a cell size based on your atom sizes (diameter ~ 28–44)
  // bigger cell = more spacing between atoms
  const cell = 42; // try 38–50
  const rowStep = cell * 0.8660254; // sqrt(3)/2

  let row = 0;

  for (
    let y = margin;
    y <= height - margin && atoms.length < NUM_ATOMS;
    y += rowStep
  ) {
    const xOffset = (row % 2) * (cell / 2);

    for (
      let x = margin + xOffset;
      x <= width - margin && atoms.length < NUM_ATOMS;
      x += cell
    ) {
      const a = new FissileAtom(x, y, {
        radius: random(14, 22),
        baseDecay: 0.00002,
        absorbGain: 0.28,
        threshold: 1.0,
      });

      // Hex grid looks best if atoms don't drift; set to 0
      a.velocity.set(0, 0);

      atoms.push(a);
    }

    row++;
  }

  // Kickstart: inject one neutron from center
  const n = new FreeNeutron(width / 2, height / 2, { life: 220, energy: 1.0 });
  n.velocity = p5.Vector.random2D().mult(5.5);
  neutrons.push(n);
}

function draw() {
  background(245);

  // --- update + draw atoms ---
  for (const a of atoms) {
    // optional slight motion
    a.update();
    a.bounceEdges();

    a.updateAtom();
    a.display();
  }

  // --- update + draw neutrons + interactions ---
  for (const n of neutrons) {
    n.updateNeutron();
    n.tryHitAtoms(atoms);
    n.display();
  }

  // --- fission step: atoms that reached threshold emit new neutrons ---
  for (const a of atoms) {
    if (a.readyToFission()) {
      const newborn = a.fission(); // returns array of FreeNeutron
      neutrons.push(...newborn);
    }
  }

  // --- cleanup dead neutrons ---
  neutrons = neutrons.filter((n) => !n.dead);



  // If you want infinite loop prevention when it gets huge:
  // neutrons = neutrons.slice(-2000);
}

function mousePressed() {
  const n = new FreeNeutron(mouseX, mouseY, {
    life: 220,
    energy: 1.0,
    radius: 4,
  });

  // give it a fast random direction (or aim to center — your call)
  n.velocity = p5.Vector.random2D().mult(5.5);

  neutrons.push(n);
}

