// emitter.js
class Emitter extends Mover {
  constructor(x, y, opts = {}) {
    super(x, y);

    this.radius = opts.radius ?? 8;

    // Emit one neutron every N frames
    this.spawnEvery = opts.spawnEvery ?? 10;

    // Neutron parameters
    this.speedMin = opts.speedMin ?? 3.5;
    this.speedMax = opts.speedMax ?? 6.5;

    this.neutronLife = opts.neutronLife ?? 220;
    this.neutronEnergy = opts.neutronEnergy ?? 1.0;
    this.neutronRadius = opts.neutronRadius ?? 1.0;

    // Burst mode (optional)
    this.burstCount = opts.burstCount ?? 1;

    this._t = 0;
  }

  updateEmitter(neutronsArray) {
    this._t++;
    if (this._t % this.spawnEvery !== 0) return;

    for (let i = 0; i < this.burstCount; i++) {
      const angle = random(TWO_PI);
      const speed = random(this.speedMin, this.speedMax);

      const n = new FreeNeutron(this.position.x, this.position.y, {
        life: this.neutronLife,
        energy: this.neutronEnergy,
        radius: this.neutronRadius,
      });

      n.velocity = p5.Vector.fromAngle(angle).mult(speed);
      neutronsArray.push(n);
    }
  }

  display() {
    push();
    noStroke();
    fill(0);
    circle(this.position.x, this.position.y, this.radius * 2);

    // crosshair
    stroke(255);
    strokeWeight(2);
    line(this.position.x - 6, this.position.y, this.position.x + 6, this.position.y);
    line(this.position.x, this.position.y - 6, this.position.x, this.position.y + 6);

    pop();
  }
}

