// sketch.js
let atoms = [];
let neutrons = [];
let emitter;

const GRID = {
  margin: 50,
  cell: 20, // smaller = more atoms
};

function setup() {
  createCanvas(600, 600);

  atoms = buildHexAtomGrid(GRID.margin, GRID.cell);

  neutrons = [];

  emitter = new Emitter(width / 2, height / 2, {
    spawnEvery: 10,      // frames
    burstCount: 1,       // try 2–4 for faster chain reaction
    speedMin: 3.5,
    speedMax: 6.5,
    neutronLife: 220,
    neutronEnergy: 1.0,
    neutronRadius: 1.0,
    radius: 8,
  });
}

function draw() {


  // Emit neutrons from the center
  emitter.updateEmitter(neutrons);
  emitter.display();

  // Atoms
  for (const a of atoms) {
    // Keep grid stable (velocity is 0), but safe to call
    a.update();
    a.bounceEdges();

    a.updateAtom();
    a.display();
  }

  // Neutrons
  for (const n of neutrons) {
    n.updateNeutron();
    n.tryHitAtoms(atoms);
    n.display();
  }

  // Fission step
  for (const a of atoms) {
    if (a.readyToFission()) {
      const newborn = a.fission();
      neutrons.push(...newborn);
    }
  }

  // Cleanup
  neutrons = neutrons.filter((n) => !n.dead);
  filter(BLUR);
  // Optional safety cap
  // if (neutrons.length > 5000) neutrons = neutrons.slice(-5000);
}

function buildHexAtomGrid(margin, cell) {
  const out = [];
  const rowStep = cell * 0.8660254; // sqrt(3)/2
  let row = 0;

  for (let y = margin; y <= height - margin; y += rowStep) {
    const xOffset = (row % 2) * (cell / 2);

    for (let x = margin + xOffset; x <= width - margin; x += cell) {
      const a = new FissileAtom(x, y, {
        radius: random(1, 2),
        baseDecay: 0.00002,
        absorbGain: 0.28,
        threshold: 1.0,
      });

      a.velocity.set(0, 0); // lock into grid
      out.push(a);
    }

    row++;
  }

  return out;
}

