// sketch.js
let atoms = [];
let neutrons = [];
let emitter;

const GRID = {
  margin: 50,
  cell: 20, // smaller = more atoms
};

const SIM = {
  neutronCap: 4000, // safety
  hashCell: 22,     // should be ~GRID.cell (or slightly larger)
};

let atomHash;

function setup() {
  createCanvas(600, 600);

  atoms = buildHexAtomGrid(GRID.margin, GRID.cell);
  neutrons = [];

  emitter = new Emitter(width / 2, height / 2, {
    spawnEvery: 10,
    burstCount: 1,
    speedMin: 3.5,
    speedMax: 6.5,
    neutronLife: 220,
    neutronEnergy: 1.0,
    neutronRadius: 1.0,
    radius: 8,
  });

  atomHash = new SpatialHash(SIM.hashCell);
  atomHash.build(atoms);
}

function draw() {
  background(245);

  // emitter
  emitter.updateEmitter(neutrons);
  emitter.display();

  // atoms update + display
  for (const a of atoms) {
    a.updateAtom();
    a.display();
  }

  // neutrons update + collide (FAST using spatial hash)
  for (const n of neutrons) {
    n.updateNeutron();

    if (!n.dead && !n.hasHit) {
      const candidates = atomHash.queryNeighbors(n.position.x, n.position.y);
      n.tryHitAtoms(candidates);
    }

    n.display();
  }

  // fission step
  for (const a of atoms) {
    if (a.readyToFission()) {
      const newborn = a.fission();
      neutrons.push(...newborn);
    }
  }

  // cleanup neutrons
  neutrons = neutrons.filter((n) => !n.dead);

  // safety cap (keeps newest)
  if (neutrons.length > SIM.neutronCap) {
    neutrons = neutrons.slice(neutrons.length - SIM.neutronCap);
  }

  // cleanup atoms (remove fully fissioned atoms)
  // If you want "spent" atoms to remain visible, change this to keep them.
  atoms = atoms.filter((a) => !a.dead);

  // rebuild hash only if atom list changed a lot (cheap anyway)
  atomHash.build(atoms);
}

function buildHexAtomGrid(margin, cell) {
  const out = [];
  const rowStep = cell * 0.8660254; // sqrt(3)/2
  let row = 0;

  for (let y = margin; y <= height - margin; y += rowStep) {
    const xOffset = (row % 2) * (cell / 2);

    for (let x = margin + xOffset; x <= width - margin; x += cell) {
      const a = new FissileAtom(x, y, {
