// neutron.js
class FreeNeutron extends Mover {
  constructor(x, y, opts = {}) {
    super(x, y);

    this.radius = opts.radius ?? 1.2;
    this.life = opts.life ?? 220;
    this.energy = opts.energy ?? 1.0;

    this.hasHit = false;
    this.dead = false;
  }

  updateNeutron() {
    if (this.dead) return;

    this.update();
    this.bounceEdges();

    this.life -= 1;
    this.energy *= 0.995;

    if (this.life <= 0 || this.energy < 0.05) {
      this.dead = true;
    }
  }

  tryHitAtoms(atoms) {
    if (this.dead || this.hasHit) return;

    for (const atom of atoms) {
      if (atom.dead || atom.fissioned || atom.exploding) continue;

      // quick reject
      const dx = this.position.x - atom.position.x;
      const dy = this.position.y - atom.position.y;
      const hitDist = this.radius + atom.radius;

      if (dx * dx + dy * dy <= hitDist * hitDist) {
        atom.absorb(this);
        this.hasHit = true;
        this.dead = true;
        break;
      }
    }
  }

  display() {
    if (this.dead) return;
    push();
    noStroke();
    fill("#F6AE2D");
    circle(this.position.x, this.position.y, this.radius * 2);
    pop();
  }
}

